SELECT DISTINCT ?name ?ftype ?county_name WHERE {
  # Select water bodies along with their names, type, and comid
  ?waterbody rdf:type hyf:HY_WaterBody ;
             schema:name ?name ;
             nhdplusv2:hasFTYPE ?ftype ;
             nhdplusv2:hasCOMID ?comid .
  # Keep only water bodies with the desired names
  VALUES ?name { 'Great Pond' 'Long Pond' }
  ?s2cell spatial:connectedTo ?waterbody ;
          rdf:type kwg-ont:S2Cell_Level13 .
  ?county spatial:connectedTo ?s2cell ;
          rdf:type kwg-ont:AdministrativeRegion_2 ;
          rdfs:label ?county_name .
  FILTER regex(str(?county), "datacommons")
} ORDER BY ?name ?county_name

